display.text:
package taskengine

import (
	"context"
	"fmt"
	"time"

	"github.com/jackc/pgx/v5/pgtype"
	"github.com/teambition/rrule-go"

	"github.com/sargunv/tend/server/internal/activitylog"
	"github.com/sargunv/tend/server/internal/database"
	dbgen "github.com/sargunv/tend/server/internal/database/gen"
	"github.com/sargunv/tend/server/internal/types"
)

// ValidateRecurrence checks that the recurrence_type and recurrence_rule
// combination is valid. Call this on both create and update paths.
// The now parameter is used for time-dependent validation (e.g., UNTIL cap).
func ValidateRecurrence(recurrenceType dbgen.RecurrenceType, recurrenceRule pgtype.Text, now time.Time) error {
	switch recurrenceType {
	case dbgen.RecurrenceTypeOneOff, dbgen.RecurrenceTypeOnDependency:
		if recurrenceRule.Valid {
			return types.ValidationError(fmt.Sprintf("recurrence_rule must not be set for %s tasks", recurrenceType))
		}
	case dbgen.RecurrenceTypeCompletionBased, dbgen.RecurrenceTypeFixedNonAccumulating, dbgen.RecurrenceTypeFixedAccumulating:
		if !recurrenceRule.Valid {
			return types.ValidationError(fmt.Sprintf("recurrence_rule is required for %s tasks", recurrenceType))
		}
		if err := validateRRule(recurrenceRule.String, now); err != nil {
			return err
		}
	default:
		return types.ValidationError(fmt.Sprintf("invalid recurrence_type %q", recurrenceType))
	}
	return nil
}

// validateRRule parses an RRULE string and rejects unsupported properties.
func validateRRule(rule string, now time.Time) error {
	opt, err := rrule.StrToROption(rule)
	if err != nil {
		return types.ValidationError(fmt.Sprintf("invalid recurrence_rule: %v", err))
	}

	switch opt.Freq {
	case rrule.YEARLY, rrule.MONTHLY, rrule.WEEKLY, rrule.DAILY:
		// supported
	case rrule.HOURLY, rrule.MINUTELY, rrule.SECONDLY:
		return types.ValidationError("unsupported RRULE frequency: must be DAILY, WEEKLY, MONTHLY, or YEARLY")
	}

	if opt.Count > 0 {
		return types.ValidationError("RRULE COUNT is not supported; use UNTIL for finite recurrence")
	}

	if !opt.Until.IsZero() && opt.Until.After(now.AddDate(10, 0, 0)) {
		return types.ValidationError("RRULE UNTIL must not exceed 10 years in the future")
	}

	if len(opt.Byhour) > 0 {
		return types.ValidationError("unsupported RRULE property: BYHOUR")
	}
	if len(opt.Byminute) > 0 {
		return types.ValidationError("unsupported RRULE property: BYMINUTE")
	}
	if len(opt.Bysecond) > 0 {
		return types.ValidationError("unsupported RRULE property: BYSECOND")
	}

	if len(opt.Bysetpos) > 0 {
		return types.ValidationError("unsupported RRULE property: BYSETPOS")
	}
	if len(opt.Byyearday) > 0 {
		return types.ValidationError("unsupported RRULE property: BYYEARDAY")
	}
	if len(opt.Byweekno) > 0 {
		return types.ValidationError("unsupported RRULE property: BYWEEKNO")
	}

	return nil
}

// ComputeNextDueAt computes the next DueDate for a recurring task after a
// completion event. Returns nil if no next occurrence exists (rule exhausted)
// or if the recurrence type does not advance the due date. The returned
// DueDate preserves the timezone from the input (defaulting to "UTC").
//
//   - completion_based: DTSTART is now (completion time) in the task's timezone.
//   - fixed_non_accumulating / fixed_accumulating: DTSTART is the current due date
//     in the task's timezone; next occurrence after now.
//
// Precondition: ValidateRecurrence must have been called first.
func ComputeNextDueAt(recurrenceType dbgen.RecurrenceType, recurrenceRule pgtype.Text, due *types.DueDate, now time.Time) (*types.DueDate, error) {
	tz := "UTC"
	if due != nil {
		tz = due.Tz
	}
	loc, err := time.LoadLocation(tz)
	if err != nil {
		return nil, types.ValidationError(fmt.Sprintf("invalid due_tz %q: %v", tz, err))
	}

	nowInTz := now.In(loc)

	var nextDate *time.Time
	switch recurrenceType {
	case dbgen.RecurrenceTypeCompletionBased:
		nextDate, err = nextRRuleOccurrence(recurrenceRule.String, nowInTz, nowInTz)
	case dbgen.RecurrenceTypeFixedNonAccumulating, dbgen.RecurrenceTypeFixedAccumulating:
		dtstart := nowInTz
		if due != nil {
			dtstart, err = due.MidnightInTz()
			if err != nil {
				return nil, err
			}
		}
		nextDate, err = nextRRuleOccurrence(recurrenceRule.String, dtstart, nowInTz)
	case dbgen.RecurrenceTypeOneOff, dbgen.RecurrenceTypeOnDependency:
		return nil, nil
	default:
		return nil, fmt.Errorf("unhandled recurrence type %q", recurrenceType)
	}
	if err != nil {
		return nil, err
	}
	if nextDate == nil {
		return nil, nil
	}
	return types.DueDateFromLocal(*nextDate, tz), nil
}

// nextRRuleOccurrence parses the rule, sets dtstart, and finds the first
// occurrence strictly after `after`. Returns nil if no future occurrence exists.
func nextRRuleOccurrence(rule string, dtstart time.Time, after time.Time) (*time.Time, error) {
	opt, err := rrule.StrToROption(rule)
	if err != nil {
		return nil, fmt.Errorf("invalid recurrence_rule: %w", err)
	}
	opt.Dtstart = dtstart

	rr, err := rrule.NewRRule(*opt)
	if err != nil {
		return nil, fmt.Errorf("invalid recurrence_rule: %w", err)
	}

	next := rr.After(after, false)
	if next.IsZero() {
		return nil, nil
	}

	midnight := time.Date(next.Year(), next.Month(), next.Day(), 0, 0, 0, 0, next.Location())
	return &midnight, nil
}

// InitialStatusFromSlice returns the name of the first initial-category status
// from a pre-fetched slice. Returns a validation error if none exists.
func InitialStatusFromSlice(statuses []dbgen.TaskStatus) (string, error) {
	for _, s := range statuses {
		if s.Category == dbgen.StatusCategoryInitial {
			return s.Name, nil
		}
	}
	return "", types.ValidationError("space has no initial status")
}

// FindInitialStatus returns the name of the first initial-category status in
// the space. Returns a validation error if no initial status exists.
func FindInitialStatus(ctx context.Context, db database.DB, spaceSlug string) (string, error) {
	q := dbgen.New(db)
	statuses, err := q.ListTaskStatusesBySpace(ctx, spaceSlug)
	if err != nil {
		return "", err
	}
	return InitialStatusFromSlice(statuses)
}

// ApplyCompletionTriggers resets tasks that have a "triggers" relation from
// the completed task. Only resets tasks with on_dependency recurrence type.
// Single-level only — ResetTaskToInitial writes directly to the DB and does not
// re-enter the update handler, so trigger cascades cannot occur.
func ApplyCompletionTriggers(ctx context.Context, db database.DB, completedTaskID int64, spaceSlug string, now pgtype.Timestamptz) error {
	q := dbgen.New(db)
	targets, err := q.ListTriggerTargets(ctx, dbgen.ListTriggerTargetsParams{
		SourceTaskID: completedTaskID,
		SpaceSlug:    spaceSlug,
	})
	if err != nil {
		return err
	}

	if len(targets) == 0 {
		return nil
	}

	initialStatus, err := FindInitialStatus(ctx, db, spaceSlug)
	if err != nil {
		return err
	}

	for _, targetID := range targets {
		target, err := q.GetTask(ctx, dbgen.GetTaskParams{ID: targetID, SpaceSlug: spaceSlug})
		if err != nil {
			return err
		}
		if target.RecurrenceType != dbgen.RecurrenceTypeOnDependency {
			continue
		}
		if err := q.ResetTaskToInitial(ctx, dbgen.ResetTaskToInitialParams{
			StatusName:   initialStatus,
			UpdatedAt:    now,
			ID:           target.ID,
			SpaceSlug:    spaceSlug,
			StatusName_2: initialStatus,
		}); err != nil {
			return err
		}

		// Log dependency trigger (system action — user who completed the trigger task is in context).
		if err := activitylog.Log(ctx, db, activitylog.Entry{
			SpaceSlug:  spaceSlug,
			EntityType: activitylog.EntityTask,
			EntityID:   types.FormatTaskID(targetID),
			Action:     activitylog.ActionUpdated,
			Details: []activitylog.Detail{
				{Field: "status", To: new(initialStatus)},
				{Field: "triggered_by", To: new(types.FormatTaskID(completedTaskID))},
			},
		}, now.Time); err != nil {
			return err
		}
	}

	return nil
}

package api_test

import (
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net"
	"net/http"
	"net/http/httptest"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/jackc/pgx/v5/pgtype"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/zitadel/oidc/v3/example/server/exampleop"
	"github.com/zitadel/oidc/v3/example/server/storage"
	"golang.org/x/text/language"

	"github.com/sargunv/tend/server/internal/api"
	"github.com/sargunv/tend/server/internal/database"
	dbgen "github.com/sargunv/tend/server/internal/database/gen"
	"github.com/sargunv/tend/server/internal/taskengine"
)

const (
	testOIDCClientID     = "tend-test"
	testOIDCClientSecret = "tend-test-secret" //nolint:gosec // test credentials
	testOIDCUserPassword = "password"         //nolint:gosec // test credentials
)

// testOIDCUserStore implements storage.UserStore with dynamic user addition.
// All methods are safe for concurrent use.
type testOIDCUserStore struct {
	mu    sync.RWMutex
	users map[string]*storage.User
}

func (s *testOIDCUserStore) GetUserByID(id string) *storage.User {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.users[id]
}

func (s *testOIDCUserStore) GetUserByUsername(u string) *storage.User {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.users[u]
}

func (s *testOIDCUserStore) ExampleClientID() string { return testOIDCClientID }

func (s *testOIDCUserStore) addUser(subject, email string, emailVerified bool) {
	s.mu.Lock()
	defer s.mu.Unlock()
	// Use subject as both ID and username so the OP can look up by either.
	s.users[subject] = &storage.User{
		ID:                subject,
		Username:          subject,
		Password:          testOIDCUserPassword,
		FirstName:         "Test",
		LastName:          "User",
		Email:             email,
		EmailVerified:     emailVerified,
		PreferredLanguage: language.English,
	}
}

type testEnv struct {
	Server  *httptest.Server
	Token   string
	Handler *api.Handler
	pool    *pgxpool.Pool
	oidc    *testOIDCUserStore
}

// addOIDCUser registers a user in the test OIDC provider's user store.
// The user authenticates with the subject as username and "password" as password.
// Panics if OIDC is not enabled on this test environment.
func (e *testEnv) addOIDCUser(subject, email string, emailVerified bool) {
	if e.oidc == nil {
		panic("addOIDCUser called on testEnv without OIDC enabled (use withOIDC())")
	}
	e.oidc.addUser(subject, email, emailVerified)
}

type testServerOption func(*testServerConfig)

type testServerConfig struct {
	oidc            bool
	oidcLinkConsent bool
}

// withOIDC enables OIDC routes on the test server using a zitadel example OP.
func withOIDC() testServerOption {
	return func(cfg *testServerConfig) {
		cfg.oidc = true
	}
}

// withOIDCLinkConsent enables OIDC link consent on the test server.
func withOIDCLinkConsent() testServerOption {
	return func(cfg *testServerConfig) {
		cfg.oidcLinkConsent = true
	}
}

func setupTestServer(t *testing.T, opts ...testServerOption) *testEnv {
	t.Helper()
	ctx := t.Context()

	var cfg testServerConfig
	for _, opt := range opts {
		opt(&cfg)
	}

	// Create a fresh database from the pre-migrated template.
	dbName := "test_" + strings.ReplaceAll(strings.ToLower(t.Name()), "/", "_")

	adminPool, err := pgxpool.New(ctx, testDSN)
	if err != nil {
		t.Fatalf("connect to test postgres: %v", err)
	}
	if _, err := adminPool.Exec(ctx, fmt.Sprintf("CREATE DATABASE %s TEMPLATE %s", dbName, testTemplateName)); err != nil {
		adminPool.Close()
		t.Fatalf("create test database: %v", err)
	}
	adminPool.Close()

	dsn := fmt.Sprintf("postgres://postgres:postgres@localhost:%d/%s?sslmode=disable", testPort, dbName)

	// Open pgx pool for the test.
	pool, err := database.OpenPool(ctx, dsn)
	if err != nil {
		t.Fatalf("open pool: %v", err)
	}
	t.Cleanup(func() {
		pool.Close()
		// Drop the test database.
		adminPool, err := pgxpool.New(ctx, testDSN)
		if err == nil {
			_, _ = adminPool.Exec(ctx, fmt.Sprintf("DROP DATABASE %q", dbName))
			adminPool.Close()
		}
	})

	// Create a test owner user.
	user, err := taskengine.CreateUserWithPassword(ctx, pool, "test@example.com", "Test User", "password", true, nil, time.Now())
	if err != nil {
		t.Fatalf("create user: %v", err)
	}

	// Create a test auth token.
	rawToken := "test-token-for-integration-tests"
	hash := sha256.Sum256([]byte(rawToken))
	tokenHash := hex.EncodeToString(hash[:])

	q := dbgen.New(pool)
	_, err = q.CreateAuthToken(ctx, dbgen.CreateAuthTokenParams{
		UserID:    user.ID,
		TokenHash: tokenHash,
		Name:      "test",
		Kind:      dbgen.AuthTokenKindSession,
		CreatedAt: pgtype.Timestamptz{Time: time.Now(), Valid: true},
	})
	if err != nil {
		t.Fatalf("create token: %v", err)
	}

	log := slog.New(slog.DiscardHandler)
	handler := &api.Handler{Pool: pool, Log: log, PasswordAuthEnabled: true}

	var oidcUserStore *testOIDCUserStore
	if cfg.oidc {
		handler.OIDCEnabled = true
		handler.OIDCLabel = "Test OIDC"
		if cfg.oidcLinkConsent {
			handler.OIDCLinkConsentEnabled = true
			linkCH, err := api.NewLinkCookieHandler(false)
			if err != nil {
				t.Fatalf("new link cookie handler: %v", err)
			}
			handler.LinkCookieHandler = linkCH
		}
	}

	h, err := api.NewServer(handler, log)
	if err != nil {
		t.Fatalf("new server: %v", err)
	}

	var srv *httptest.Server
	if cfg.oidc {
		// Start a zitadel example OP on a random port.
		userStore := &testOIDCUserStore{users: make(map[string]*storage.User)}
		clients := map[string]*storage.Client{}
		// Pre-allocate a listener for the test server so we know the
		// callback URL before starting the OP (which needs it for client registration).
		var lc net.ListenConfig
		srvLn, err := lc.Listen(ctx, "tcp", "127.0.0.1:0")
		if err != nil {
			t.Fatalf("listen for test server: %v", err)
		}
		callbackURL := "http://" + srvLn.Addr().String() + "/auth/oidc/callback"
		clients[testOIDCClientID] = storage.WebClient(testOIDCClientID, testOIDCClientSecret, callbackURL)

		// Start the OP on its own listener.
		opLn, err := lc.Listen(ctx, "tcp", "127.0.0.1:0")
		if err != nil {
			_ = srvLn.Close()
			t.Fatalf("listen for oidc op: %v", err)
		}
		opIssuer := "http://" + opLn.Addr().String() + "/"
		stor := storage.NewStorageWithClients(userStore, clients)
		opRouter := exampleop.SetupServer(opIssuer, stor, log, false)
		opServer := &http.Server{Handler: opRouter, ReadHeaderTimeout: 10 * time.Second}
		go func() {
			if err := opServer.Serve(opLn); err != nil && !errors.Is(err, http.ErrServerClosed) {
				t.Errorf("oidc op server exited unexpectedly: %v", err)
			}
		}()
		t.Cleanup(func() { _ = opServer.Close() })

		oidcUserStore = userStore

		// Configure the test server's OIDC handler to use the OP.
		oidcCfg := api.OIDCConfig{
			Issuer:       opIssuer,
			ClientID:     testOIDCClientID,
			ClientSecret: testOIDCClientSecret,
			RedirectURL:  callbackURL,
		}
		oidcHandler, err := api.NewOIDCHandler(ctx, oidcCfg, handler)
		if err != nil {
			_ = srvLn.Close()
			t.Fatalf("new oidc handler: %v", err)
		}
		composed := api.MountOAuth(api.MountWebAuth(api.MountOIDC(h, oidcHandler, log), handler), handler)
		srv = httptest.NewUnstartedServer(composed)
		srv.Listener = srvLn
		srv.Start()
	} else {
		srv = httptest.NewServer(api.MountOAuth(api.MountWebAuth(h, handler), handler))
	}
	t.Cleanup(srv.Close)

	return &testEnv{
		Server:  srv,
		Token:   rawToken,
		Handler: handler,
		pool:    pool,
		oidc:    oidcUserStore,
	}
}

func doRequestAs(t *testing.T, env *testEnv, token, method, path, body string) *http.Response {
	t.Helper()
	var bodyReader io.Reader
	if body != "" {
		bodyReader = strings.NewReader(body)
	}
	req, err := http.NewRequestWithContext(t.Context(), method, env.Server.URL+path, bodyReader)
	if err != nil {
		t.Fatalf("new request: %v", err)
	}
	if body != "" {
		req.Header.Set("Content-Type", "application/json")
	}
	if token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		t.Fatalf("do request: %v", err)
	}
	return resp
}

func doRequest(t *testing.T, env *testEnv, method, path, body string) *http.Response {
	t.Helper()
	return doRequestAs(t, env, env.Token, method, path, body)
}

// createTestUser creates a non-owner user via the DB and logs them in to get a session token.
func createTestUser(t *testing.T, env *testEnv, email, name, password string) string {
	t.Helper()
	_, err := taskengine.CreateUserWithPassword(t.Context(), env.pool, email, name, password, false, nil, time.Now())
	if err != nil {
		t.Fatalf("create test user: %v", err)
	}

	// Login via web endpoint to get a session cookie.
